DELETE FROM payroll_batch_corrections;
DELETE FROM payroll_batch_notes;
DELETE FROM payroll_batch_items;
DELETE FROM payroll_batches;

-- Show remaining counts
SELECT 
  'payroll_batches' as table_name, 
  COUNT(*) as count 
FROM payroll_batches
UNION ALL
SELECT 'payroll_batch_items', COUNT(*) FROM payroll_batch_items
UNION ALL
SELECT 'payroll_batch_notes', COUNT(*) FROM payroll_batch_notes
UNION ALL
SELECT 'payroll_batch_corrections', COUNT(*) FROM payroll_batch_corrections;

